// ============================================================
// getTestQuestionsForDay — Main Export Function
// ============================================================
// Returns test questions for any day (1-75)
// Priority: ALL_TEST_QUESTIONS → EXTENDED_TEST_QUESTIONS → fallback generator

export function getTestQuestionsForDay(dayNum) {
  // Preserve existing handcrafted questions first, then extend to the requested 400-question target
  const existingQuestions = ALL_TEST_QUESTIONS[dayNum] || (EXTENDED_TEST_QUESTIONS && EXTENDED_TEST_QUESTIONS[dayNum]) || generateFallbackTestQuestions(dayNum);
  return ensureTestTarget(dayNum, existingQuestions, 400); // Guarantee 400 MCQ-ready test questions for every day
}

// ============================================================
// Fallback Generator for missing days (safety net only)
// ============================================================
function generateFallbackTestQuestions(dayNum) {
  // Basic fallback MCQ questions generated from day number
  const questions = [];
  for (let i = 1; i <= 20; i++) {
    questions.push({
      id: `d${String(dayNum).padStart(2,'0')}-t${String(i).padStart(3,'0')}`,
      hindi: `Day ${dayNum} — Practice Question ${i}`,
      options: ['Option A', 'Option B', 'Option C', 'Option D'],
      correct: 0,
      explanation: `This is a fallback question for Day ${dayNum}. Please check testData files.`,
      type: 'mcq',
      difficulty: 'easy',
      marks: 1,
    });
  }
  return questions;
}

